      const q = search.toLowerCase();
      const filtered = prices.filter(p =>
        p.ingredient_name.toLowerCase().includes(q) ||
        p.category.toLowerCase().includes(q) ||
        (p.supplier && p.supplier.toLowerCase().includes(q))
