// â”€â”€ CSS-only donut chart â”€â”€

const DONUT_COLORS = [
  '#14b8a6', // teal
  '#8b5cf6', // violet
  '#f59e0b', // amber
  '#ef4444', // red
  '#3b82f6', // blue
];

function DonutChart({
  data,
  total,
}: {
  data: { category: string; count: number; foodCost: number }[];
  total: number;
}) {
  if (total === 0) return null;

  // Build conic gradient
  let accumulated = 0;
  const segments = data.map((d, i) => {
    const pct = (d.count / total) * 100;
    const start = accumulated;
    accumulated += pct;
    return { ...d, pct, start, end: accumulated, color: DONUT_COLORS[i % DONUT_COLORS.length] };
  });

  const gradient = segments
    .map((s) => `${s.color} ${s.start}% ${s.end}%`)
    .join(', ');

  return (
    <div className="flex items-center gap-4">
      <div
        className="w-20 h-20 rounded-full shrink-0 relative"
        style={{
          background: `conic-gradient(${gradient})`,
        }}
      >
        {/* Inner circle for donut effect */}
        <div className="absolute inset-2.5 rounded-full bg-slate-800" />
        <div className="absolute inset-0 flex items-center justify-center">
          <span className="text-xs font-bold text-white">{total}</span>
        </div>
      </div>
      <div className="space-y-1.5 flex-1 min-w-0">
        {segments.map((s) => (

      totalSales,
      avgMargin: Math.round(avgMarginPct * 10) / 10,
      days: daysNum || Math.ceil((new Date(customTo).getTime() - new Date(customFrom).getTime()) / 86400000) || 30,
    });
  } catch (err: unknown) {
    const message = err instanceof Error ? err.message : 'Erreur de chargement';
    showToast(message, 'error');
  } finally {
    setLoading(false);
  }
}, [period, customFrom, customTo, showToast]);

